import sqlite3


# --- Model registry for resolving string references ---
_MODEL_REGISTRY: dict[str, type] = {}


class Column:

    def __init__(self, col_type: str, primary_key: bool = False,
                 nullable: bool = True, foreign_key: str | None = None):
        self.col_type = col_type
        self.primary_key = primary_key
        self.nullable = nullable
        self.foreign_key = foreign_key
        self.name = ''

    def __set_name__(self, owner, name):
        self.name = name


class Relationship:

    def __init__(self, target_model: str, back_populates: str | None = None):
        self.target_model = target_model
        self.back_populates = back_populates
        self.name = ''

    def __set_name__(self, owner, name):
        self.name = name


class ModelMeta(type):

    def __new__(mcs, name, bases, namespace):
        columns = {}
        relationships = {}
        for key, val in namespace.items():
            if isinstance(val, Column):
                columns[key] = val
            elif isinstance(val, Relationship):
                relationships[key] = val
        # Also inherit from base classes
        for base in bases:
            if hasattr(base, '__columns__'):
                for k, v in base.__columns__.items():
                    columns.setdefault(k, v)
            if hasattr(base, '__relationships__'):
                for k, v in base.__relationships__.items():
                    relationships.setdefault(k, v)

        namespace['__columns__'] = columns
        namespace['__relationships__'] = relationships
        # Auto-generate table name as lowercase class name + 's'
        if name != 'Model':
            namespace['__tablename__'] = name.lower() + 's'

        cls = super().__new__(mcs, name, bases, namespace)
        # Register non-base classes in the global registry
        if name != 'Model':
            _MODEL_REGISTRY[name] = cls
        return cls


class Model(metaclass=ModelMeta):

    def __init__(self, **kwargs):
        # Set column attributes from kwargs, defaulting to None
        for col_name in self.__columns__:
            setattr(self, col_name, kwargs.get(col_name))
        # Initialize relationship attributes as empty lists
        for rel_name in self.__relationships__:
            setattr(self, rel_name, [])

    def to_dict(self) -> dict:
        # Return only column values, excluding relationships
        return {name: getattr(self, name) for name in self.__columns__}

    @classmethod
    def create_table_sql(cls) -> str:
        # Build CREATE TABLE with column definitions and FOREIGN KEY constraints
        parts = []
        fk_constraints = []
        for col_name, col in cls.__columns__.items():
            definition = f"{col_name} {col.col_type}"
            if col.primary_key:
                definition += " PRIMARY KEY AUTOINCREMENT"
            if not col.nullable and not col.primary_key:
                definition += " NOT NULL"
            parts.append(definition)
            # Collect foreign key constraints separately
            if col.foreign_key:
                ref_table, ref_col = col.foreign_key.split('.')
                fk_constraints.append(
                    f"FOREIGN KEY({col_name}) REFERENCES {ref_table}({ref_col})"
                )
        all_parts = parts + fk_constraints
        cols_sql = ", ".join(all_parts)
        return f"CREATE TABLE IF NOT EXISTS {cls.__tablename__} ({cols_sql})"


class Session:

    def __init__(self, conn: sqlite3.Connection):
        self.conn = conn
        self._registry: dict[str, type] = {}

    def register(self, *model_classes) -> None:
        for cls in model_classes:
            self._registry[cls.__name__] = cls

    def create_table(self, model_cls) -> None:
        self.conn.execute(model_cls.create_table_sql())

    def add(self, instance) -> None:
        # INSERT row, skipping primary key columns (auto-increment)
        cols = {name: getattr(instance, name)
                for name, col in instance.__columns__.items()
                if not col.primary_key}
        col_names = ", ".join(cols.keys())
        placeholders = ", ".join("?" for _ in cols)
        sql = f"INSERT INTO {instance.__tablename__} ({col_names}) VALUES ({placeholders})"
        cursor = self.conn.execute(sql, list(cols.values()))
        instance.id = cursor.lastrowid

    def get(self, model_cls, id: int):
        sql = f"SELECT * FROM {model_cls.__tablename__} WHERE id = ?"
        row = self.conn.execute(sql, (id,)).fetchone()
        if row is None:
            return None
        # Map column indices to column names
        col_names = list(model_cls.__columns__.keys())
        instance = model_cls(**dict(zip(col_names, row)))
        return instance

    def all(self, model_cls) -> list:
        sql = f"SELECT * FROM {model_cls.__tablename__}"
        rows = self.conn.execute(sql).fetchall()
        col_names = list(model_cls.__columns__.keys())
        return [model_cls(**dict(zip(col_names, row))) for row in rows]

    def commit(self) -> None:
        self.conn.commit()

    def load_related(self, instance, rel_attr: str) -> list:
        # Get the Relationship descriptor from the class
        rel = instance.__relationships__[rel_attr]
        # Resolve the target model class
        target_cls = self._registry[rel.target_model]
        # Find the foreign key column on the target that references
        # the parent's table
        fk_col_name = None
        for col_name, col in target_cls.__columns__.items():
            if col.foreign_key:
                ref_table = col.foreign_key.split('.')[0]
                if ref_table == instance.__tablename__:
                    fk_col_name = col_name
                    break
        if fk_col_name is None:
            return []
        # Query child table where fk matches parent id
        sql = f"SELECT * FROM {target_cls.__tablename__} WHERE {fk_col_name} = ?"
        rows = self.conn.execute(sql, (instance.id,)).fetchall()
        col_names = list(target_cls.__columns__.keys())
        related = [target_cls(**dict(zip(col_names, row))) for row in rows]
        # Store on the instance for later access
        setattr(instance, rel_attr, related)
        return related

    def get_with_related(self, model_cls, id: int, *rel_attrs: str):
        # Fetch the parent instance, then eagerly load each relationship
        instance = self.get(model_cls, id)
        if instance is None:
            return None
        for attr in rel_attrs:
            self.load_related(instance, attr)
        return instance


class User(Model):
    id = Column('INTEGER', primary_key=True)
    name = Column('TEXT', nullable=False)
    posts = Relationship('Post', back_populates='author')


class Post(Model):
    id = Column('INTEGER', primary_key=True)
    title = Column('TEXT', nullable=False)
    user_id = Column('INTEGER', foreign_key='users.id')
    author = Relationship('User', back_populates='posts')
